#include <cstdio>
#include <cstdlib>
#include <cstring>
#include <vector>
#include <string>
#include "cJSON.h"
#include "lodepng.h"

// Read entire file into a string
static std::string read_file(const char* path) {
    FILE* f = fopen(path, "rb");
    if (!f) { fprintf(stderr, "cannot open %s\n", path); exit(1); }
    fseek(f, 0, SEEK_END);
    long n = ftell(f);
    fseek(f, 0, SEEK_SET);
    std::string s;
    s.resize(n);
    if (fread(&s[0], 1, n, f) != (size_t)n) { fprintf(stderr, "read error\n"); exit(1); }
    fclose(f);
    return s;
}

// Parse a 2D array [out][in] into a flat row-major vector
static std::vector<float> parse_matrix(cJSON* arr, int& rows, int& cols) {
    rows = cJSON_GetArraySize(arr);
    cols = 0;
    std::vector<float> out;
    for (int i = 0; i < rows; i++) {
        cJSON* row = cJSON_GetArrayItem(arr, i);
        int c = cJSON_GetArraySize(row);
        if (i == 0) cols = c;
        for (int j = 0; j < c; j++) {
            out.push_back((float)cJSON_GetArrayItem(row, j)->valuedouble);
        }
    }
    return out;
}

static std::vector<float> parse_vector(cJSON* arr) {
    int n = cJSON_GetArraySize(arr);
    std::vector<float> out(n);
    for (int i = 0; i < n; i++) out[i] = (float)cJSON_GetArrayItem(arr, i)->valuedouble;
    return out;
}

// Fully-connected layer: y = W x + b, W is [out][in] row-major
static std::vector<float> linear(const std::vector<float>& x, const std::vector<float>& W,
                                 const std::vector<float>& b, int out_dim, int in_dim) {
    std::vector<float> y(out_dim);
    for (int o = 0; o < out_dim; o++) {
        float acc = b[o];
        const float* wr = &W[(size_t)o * in_dim];
        for (int i = 0; i < in_dim; i++) acc += wr[i] * x[i];
        y[o] = acc;
    }
    return y;
}

static void relu(std::vector<float>& x) {
    for (float& v : x) if (v < 0) v = 0;
}

int main(int argc, char** argv) {
    if (argc < 3) {
        fprintf(stderr, "usage: %s weights.json image.png\n", argv[0]);
        return 1;
    }

    // Load weights
    std::string json = read_file(argv[1]);
    cJSON* root = cJSON_Parse(json.c_str());
    if (!root) { fprintf(stderr, "failed to parse weights json\n"); return 1; }

    int iw_r, iw_c, hw_r, hw_c, ow_r, ow_c;
    std::vector<float> iw = parse_matrix(cJSON_GetObjectItem(root, "input_layer.weight"), iw_r, iw_c);
    std::vector<float> ib = parse_vector(cJSON_GetObjectItem(root, "input_layer.bias"));
    std::vector<float> hw = parse_matrix(cJSON_GetObjectItem(root, "hidden_layer.weight"), hw_r, hw_c);
    std::vector<float> hb = parse_vector(cJSON_GetObjectItem(root, "hidden_layer.bias"));
    std::vector<float> ow = parse_matrix(cJSON_GetObjectItem(root, "output_layer.weight"), ow_r, ow_c);
    std::vector<float> ob = parse_vector(cJSON_GetObjectItem(root, "output_layer.bias"));

    // Decode image as 8-bit grayscale
    std::vector<unsigned char> pixels;
    unsigned w = 0, h = 0;
    unsigned err = lodepng::decode(pixels, w, h, argv[2], LCT_GREY, 8);
    if (err) { fprintf(stderr, "png decode error: %s\n", lodepng_error_text(err)); return 1; }

    // Flatten and normalize to [0,1]
    std::vector<float> x(pixels.size());
    for (size_t i = 0; i < pixels.size(); i++) x[i] = pixels[i] / 255.0f;
    if ((int)x.size() != iw_c) {
        fprintf(stderr, "image size %zu != model input %d\n", x.size(), iw_c);
        return 1;
    }

    // Forward pass
    std::vector<float> a = linear(x, iw, ib, iw_r, iw_c); relu(a);
    std::vector<float> b2 = linear(a, hw, hb, hw_r, hw_c); relu(b2);
    std::vector<float> logits = linear(b2, ow, ob, ow_r, ow_c);

    int best = 0;
    for (int i = 1; i < (int)logits.size(); i++) if (logits[i] > logits[best]) best = i;

    printf("%d\n", best);

    cJSON_Delete(root);
    return 0;
}

